WebLink.url:
{!REQUIRESCRIPT("/support/console/48.0/integration.js")}

var currentTabId = '';
if (sforce.console.isInConsole()) {
    console.log("inside isinconsole");
    sforce.console.getEnclosingPrimaryTabId(openSubtab);
}
else {
    window.open("/apex/CreateCaseOrOpportunityPage?id={!Cluster_Issue__c.Id}&object=Opportunity", '_blank');
}

function openSubtab(result) {
    console.log("inside openSubtab");
    //Now that we have the primary tab ID, we can open a new subtab in it
    var primaryTabId = result.id;
    sforce.console.getEnclosingTabId(getCurrentTabId);
    sforce.console.openSubtab(primaryTabId, "/apex/CreateCaseOrOpportunityPage?id={!Cluster_Issue__c.Id}&object=Opportunity&tabId=" + currentTabId, true,
        'Opportunity', null, setOpenedTabIcon, 'salesforceSubtab');
}

function getCurrentTabId(result) {
    currentTabId = result.id;
}

function setOpenedTabIcon(result) {
    console.log("inside setOpenedTabIcon");
    if (result.success) {
        sforce.console.setTabIcon('/resource/Case_Tab_Icon', result.id, null);
    } else {
        //alert('Tab icon cannot be set!');
    }
}
